INSERT INTO t_p42562714_web_app_creation_1.site_content (key, value, description, category)
VALUES
  ('footer.notice.title', 'Внимание!', 'Заголовок информационного блока в подвале сайта', 'footer'),
  ('footer.notice.text1', 'Сайт/веб-приложение находится на стадии активной начальной разработки. В связи с этим возможны временные некорректности в работе, изменения в функционале и появление тестовых заявок. Приносим извинения за возможные неудобства.', 'Первый абзац блока «Внимание!» в подвале', 'footer'),
  ('footer.notice.text2', 'Мы верим в потенциал этого проекта и приглашаем вас стать частью его успеха! Проект нуждается в финансировании для дальнейшего развития и реализации перспективных возможностей. По вопросам спонсорства и инвестиций просим обращаться к разработчику по контактам, указанным ниже.', 'Второй абзац блока «Внимание!» в подвале', 'footer'),
  ('about.intro1', 'ЕРТТП — это современная онлайн‑платформа, созданная для поддержки и развития местного бизнеса. Мы объединяем производителей, поставщиков и потребителей, формируя устойчивую экосистему региональной торговли.', 'Первый вводный абзац страницы «О нас»', 'about'),
  ('about.intro2', 'Наша цель — сделать локальный рынок более эффективным, прозрачным и доступным для всех участников, создавая конкурентные условия, где главным преимуществом становится качество товаров и услуг.', 'Второй вводный абзац страницы «О нас»', 'about')
